# app/controllers/admin/reports_controller.rb
class Admin::ReportsController < ApplicationController
  before_action :authenticate_user!
  before_action :require_admin!

  # Predefined report templates that power users can select and parameterize
  ALLOWED_REPORTS = {
    "user_signups" => {
      description: "User signups over time",
      sql: "SELECT DATE(created_at) as signup_date, COUNT(*) as total FROM users WHERE created_at >= :start_date AND created_at <= :end_date GROUP BY DATE(created_at) ORDER BY signup_date",
      allowed_params: [:start_date, :end_date]
    },
    "revenue_by_product" => {
      description: "Revenue grouped by product",
      sql: "SELECT products.name, SUM(order_items.quantity * order_items.unit_price) as revenue FROM order_items JOIN products ON products.id = order_items.product_id JOIN orders ON orders.id = order_items.order_id WHERE orders.created_at >= :start_date AND orders.created_at <= :end_date GROUP BY products.name ORDER BY revenue DESC",
      allowed_params: [:start_date, :end_date]
    },
    "active_users" => {
      description: "Users with activity in period",
      sql: "SELECT users.email, users.created_at, COUNT(activities.id) as activity_count FROM users LEFT JOIN activities ON activities.user_id = users.id WHERE activities.created_at >= :start_date AND activities.created_at <= :end_date GROUP BY users.id, users.email, users.created_at HAVING COUNT(activities.id) >= :min_activity ORDER BY activity_count DESC LIMIT :result_limit",
      allowed_params: [:start_date, :end_date, :min_activity, :result_limit]
    },
    "order_summary" => {
      description: "Order summary statistics",
      sql: "SELECT status, COUNT(*) as order_count, SUM(total_amount) as total_revenue, AVG(total_amount) as avg_order_value FROM orders WHERE created_at >= :start_date AND created_at <= :end_date GROUP BY status ORDER BY order_count DESC",
      allowed_params: [:start_date, :end_date]
    }
  }.freeze

  MAX_RESULTS = 10_000
  QUERY_TIMEOUT_SECONDS = 30

  def index
    @available_reports = ALLOWED_REPORTS.map { |key, config| [key, config[:description]] }
    @saved_reports = SavedReport.where(created_by: current_user).order(created_at: :desc).limit(20)
  end

  def show
    @report_key = params[:id]
    @report_config = ALLOWED_REPORTS[@report_key]

    unless @report_config
      redirect_to admin_reports_path, alert: "Unknown report type."
      return
    end

    @allowed_params = @report_config[:allowed_params]
    @description = @report_config[:description]
  end

  def execute
    @report_key = params[:report_key]
    @report_config = ALLOWED_REPORTS[@report_key]

    unless @report_config
      redirect_to admin_reports_path, alert: "Unknown report type."
      return
    end

    sanitized_binds = sanitize_report_params(@report_config[:allowed_params])

    begin
      @results = execute_safe_report(@report_config[:sql], sanitized_binds)
      @columns = @results.first&.keys || []

      log_report_execution(@report_key, sanitized_binds)

      respond_to do |format|
        format.html { render :results }
        format.csv { send_csv_report(@report_key, @columns, @results) }
        format.json { render json: { columns: @columns, rows: @results, total: @results.size } }
      end
    rescue ActiveRecord::QueryCanceled
      redirect_to admin_report_path(@report_key), alert: "Query timed out. Try narrowing your date range."
    rescue ActiveRecord::StatementInvalid => e
      Rails.logger.error("Report execution error: #{e.message}")
      redirect_to admin_report_path(@report_key), alert: "Report query failed. Please contact support."
    end
  end

  # Allow admins to create new report templates (stored safely, reviewed before activation)
  def create_template
    template = ReportTemplate.new(
      name: params[:name],
      description: params[:description],
      raw_sql: params[:raw_sql],
      allowed_params: params[:param_names],
      created_by: current_user,
      status: :pending_review  # Requires another admin to review and approve
    )

    if template.save
      AdminMailer.new_report_template_for_review(template).deliver_later
      redirect_to admin_reports_path, notice: "Report template submitted for review. Another admin must approve it before use."
    else
      render :new_template, status: :unprocessable_entity
    end
  end

  private

  def require_admin!
    unless current_user&.admin?
      redirect_to root_path, alert: "Access denied."
    end
  end

  def sanitize_report_params(allowed_params)
    binds = {}

    allowed_params.each do |param_name|
      value = params.dig(:report_params, param_name)
      next if value.blank?

      binds[param_name] = case param_name
                          when :start_date, :end_date
                            Date.parse(value.to_s)
                          when :result_limit
                            [[value.to_i, 1].max, MAX_RESULTS].min
                          when :min_activity
                            [value.to_i, 0].max
                          else
                            ActiveRecord::Base.sanitize_sql_like(value.to_s)
                          end
    end

    # Apply defaults
    binds[:start_date] ||= 30.days.ago.to_date
    binds[:end_date] ||= Date.current
    binds[:result_limit] ||= 1000

    binds
  end

  def execute_safe_report(sql_template, binds)
    # Use a read-only connection/role if available
    sanitized_sql = ActiveRecord::Base.sanitize_sql_array([sql_template, binds])

    results = []

    ActiveRecord::Base.connection.execute("SET statement_timeout = '#{QUERY_TIMEOUT_SECONDS}s'") if postgresql?

    ActiveRecord::Base.connection_pool.with_connection do |conn|
      # Use a read-only transaction to prevent any writes
      conn.transaction do
        conn.execute("SET TRANSACTION READ ONLY") if postgresql?

        raw_results = conn.exec_query(sanitized_sql)
        results = raw_results.to_a

        raise ActiveRecord::Rollback # Always rollback, we only read
      end
    end

    results
  end

  def postgresql?
    ActiveRecord::Base.connection.adapter_name.downcase.include?("postgresql")
  end

  def log_report_execution(report_key, params)
    ReportAuditLog.create!(
      user: current_user,
      report_key: report_key,
      parameters: params.to_json,
      executed_at: Time.current,
      ip_address: request.remote_ip,
      user_agent: request.user_agent
    )
  end

  def send_csv_report(report_key, columns, results)
    csv_data = CSV.generate(headers: true) do |csv|
      csv << columns
      results.each { |row| csv << columns.map { |col| row[col] } }
    end

    send_data csv_data,
              filename: "#{report_key}_#{Date.current}.csv",
              type: "text/csv",
              disposition: "attachment"
  end
end